  1→/**
  2→ * ExceptionRequestModal Component
  3→ *
  4→ * Modal form for requesting vulnerability exceptions
  5→ *
  6→ * Features:
  7→ * - Scope selection (Single vulnerability or CVE pattern)
  8→ * - Reason validation (50-2048 characters with counter)
  9→ * - Future expiration date selection
 10→ * - Client-side validation
 11→ * - Success/error handling
 12→ * - Loading states
 13→ *
 14→ * Feature: 031-vuln-exception-approval
 15→ * User Story 1: Regular User Requests Exception (P1)
 16→ * Reference: spec.md FR-003, FR-004
 17→ */
 18→
 19→import React, { useState, useEffect } from 'react';
 20→import { createRequest, type CreateExceptionRequestDto, type ExceptionScope } from '../services/exceptionRequestService';
 21→import CveLink from './CveLink';
 22→
 23→interface ExceptionRequestModalProps {
 24→    isOpen: boolean;
 25→    vulnerabilityId: number;
 26→    vulnerabilityCveId: string | null;
 27→    assetName: string;
 28→    onClose: () => void;
 29→    onSuccess: () => void;
 30→}
 31→
 32→const ExceptionRequestModal: React.FC<ExceptionRequestModalProps> = ({
 33→    isOpen,
 34→    vulnerabilityId,
 35→    vulnerabilityCveId,
 36→    assetName,
 37→    onClose,
 38→    onSuccess
 39→}) => {
 40→    // Form state
 41→    const [formData, setFormData] = useState<{
 42→        scope: ExceptionScope;
 43→        reason: string;
 44→        expirationDate: string;
 45→    }>({
 46→        scope: 'SINGLE_VULNERABILITY',
 47→        reason: '',
 48→        expirationDate: '',
 49→    });
 50→
 51→    // UI state
 52→    const [loading, setLoading] = useState(false);
 53→    const [error, setError] = useState<string | null>(null);
 54→    const [validationErrors, setValidationErrors] = useState<{
 55→        reason?: string;
 56→        expirationDate?: string;
 57→    }>({});
 58→    const [showLongExpirationWarning, setShowLongExpirationWarning] = useState(false);
 59→    const [longExpirationConfirmed, setLongExpirationConfirmed] = useState(false);
 60→    const [pendingExpirationDate, setPendingExpirationDate] = useState<string | null>(null);
 61→
 62→    // Reset form when modal opens/closes
 63→    useEffect(() => {
 64→        if (isOpen) {
 65→            setFormData({
 66→                scope: 'SINGLE_VULNERABILITY',
 67→                reason: '',
 68→                expirationDate: '',
 69→            });
 70→            setError(null);
 71→            setValidationErrors({});
 72→            setLongExpirationConfirmed(false);
 73→            setPendingExpirationDate(null);
 74→            setShowLongExpirationWarning(false);
 75→        }
 76→    }, [isOpen]);
 77→
 78→    // Handle keyboard navigation (Escape to close)
 79→    useEffect(() => {
 80→        if (!isOpen) return;
 81→
 82→        function handleKeyDown(e: KeyboardEvent) {
 83→            if (e.key === 'Escape' && !loading) {
 84→                handleCancel();
 85→            }
 86→        }
 87→
 88→        document.addEventListener('keydown', handleKeyDown);
 89→        return () => document.removeEventListener('keydown', handleKeyDown);
 90→    }, [isOpen, loading]);
 91→
 92→    // Handle input changes
 93→    function handleChange(e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) {
 94→        const { name, value } = e.target;
 95→
 96→        // Special handling for expiration date - check if > 365 days
 97→        if (name === 'expirationDate' && value) {
 98→            const selectedDate = new Date(value);
 99→            const now = new Date();
100→            const daysInFuture = Math.floor((selectedDate.getTime() - now.getTime()) / (1000 * 60 * 60 * 24));
101→
102→            if (daysInFuture > 365 && !longExpirationConfirmed) {
103→                // Show warning modal
104→                setPendingExpirationDate(value);
105→                setShowLongExpirationWarning(true);
106→                return;
107→            }
108→        }
109→
110→        setFormData((prev) => ({ ...prev, [name]: value }));
111→
112→        // Clear validation error for this field
113→        setValidationErrors((prev) => ({ ...prev, [name]: undefined }));
114→        setError(null);
115→    }
116→
117→    // Handle scope radio change
118→    function handleScopeChange(e: React.ChangeEvent<HTMLInputElement>) {
119→        setFormData((prev) => ({ ...prev, scope: e.target.value as ExceptionScope }));
120→    }
121→
122→    // Handle long expiration warning confirmation
123→    function handleConfirmLongExpiration() {
124→        if (pendingExpirationDate) {
125→            setFormData((prev) => ({ ...prev, expirationDate: pendingExpirationDate }));
126→            setLongExpirationConfirmed(true);
127→        }
128→        setShowLongExpirationWarning(false);
129→        setPendingExpirationDate(null);
130→    }
131→
132→    // Handle long expiration warning rejection
133→    function handleRejectLongExpiration() {
134→        setShowLongExpirationWarning(false);
135→        setPendingExpirationDate(null);
136→        // Date field remains unchanged (user can select a different date)
137→    }
138→
139→    // Validate form
140→    function validateForm(): boolean {
141→        const errors: { reason?: string; expirationDate?: string } = {};
142→
143→        // Validate reason (50-2048 characters)
144→        const reasonLength = formData.reason.trim().length;
145→        if (reasonLength === 0) {
146→            errors.reason = 'Reason is required';
147→        } else if (reasonLength < 50) {
148→            errors.reason = `Reason must be at least 50 characters (currently ${reasonLength})`;
149→        } else if (reasonLength > 2048) {
150→            errors.reason = `Reason must not exceed 2048 characters (currently ${reasonLength})`;
151→        }
152→
153→        // Validate expiration date (must be in future)
154→        if (!formData.expirationDate) {
155→            errors.expirationDate = 'Expiration date is required';
156→        } else {
157→            const selectedDate = new Date(formData.expirationDate);
158→            const now = new Date();
159→            if (selectedDate <= now) {
160→                errors.expirationDate = 'Expiration date must be in the future';
161→            }
162→        }
163→
164→        setValidationErrors(errors);
165→        return Object.keys(errors).length === 0;
166→    }
167→
168→    // Handle form submission
169→    async function handleSubmit(e: React.FormEvent) {
170→        e.preventDefault();
171→
172→        // Validate form
173→        if (!validateForm()) {
174→            return;
175→        }
176→
177→        setLoading(true);
178→        setError(null);
179→
180→        try {
181→            // Create exception request
182→            const dto: CreateExceptionRequestDto = {
183→                vulnerabilityId,
184→                scope: formData.scope,
185→                reason: formData.reason.trim(),
186→                expirationDate: new Date(formData.expirationDate).toISOString(),
187→            };
188→
189→            await createRequest(dto);
190→
191→            // Success - close modal and notify parent
192→            onSuccess();
193→            onClose();
194→
195→        } catch (err) {
196→            const errorMessage = err instanceof Error ? err.message : 'Failed to create exception request. Please try again.';
197→            setError(errorMessage);
198→        } finally {
199→            setLoading(false);
200→        }
201→    }
202→
203→    // Handle cancel
204→    function handleCancel() {
205→        onClose();
206→    }
207→
208→    // Get character count for reason field
209→    const reasonLength = formData.reason.length;
210→    const reasonCountColor = reasonLength < 50 ? 'text-danger' : reasonLength > 2048 ? 'text-danger' : 'text-muted';
211→
212→    // Get minimum date for date picker (tomorrow)
213→    const tomorrow = new Date();
214→    tomorrow.setDate(tomorrow.getDate() + 1);
215→    const minDate = tomorrow.toISOString().split('T')[0];
216→
217→    // Don't render if not open
218→    if (!isOpen) {
219→        return null;
220→    }
221→
222→    return (
223→        <>
224→            {/* Backdrop */}
225→            <div
226→                className="modal-backdrop fade show"
227→                onClick={handleCancel}
228→                style={{ zIndex: 1040 }}
229→            ></div>
230→
231→            {/* Modal */}
232→            <div
233→                className="modal fade show d-block"
234→                tabIndex={-1}
235→                role="dialog"
236→                style={{ zIndex: 1050 }}
237→                aria-labelledby="exceptionRequestModalLabel"
238→                aria-modal="true"
239→            >
240→                <div className="modal-dialog modal-dialog-centered modal-lg">
241→                    <div className="modal-content">
242→                        {/* Header */}
243→                        <div className="modal-header">
244→                            <h5 className="modal-title" id="exceptionRequestModalLabel">
245→                                Request Vulnerability Exception
246→                            </h5>
247→                            <button
248→                                type="button"
249→                                className="btn-close"
250→                                aria-label="Close"
251→                                onClick={handleCancel}
252→                                disabled={loading}
253→                            ></button>
254→                        </div>
255→
256→                        {/* Body */}
257→                        <form onSubmit={handleSubmit}>
258→                            <div className="modal-body">
259→                                {/* Error Alert */}
260→                                {error && (
261→                                    <div className="alert alert-danger" role="alert">
262→                                        {error}
263→                                    </div>
264→                                )}
265→
266→                                {/* Vulnerability Info */}
267→                                <div className="alert alert-info mb-3">
268→                                    <div className="d-flex align-items-start">
269→                                        <i className="bi bi-shield-exclamation me-2 mt-1"></i>
270→                                        <div>
271→                                            <strong>Vulnerability:</strong> <CveLink cveId={vulnerabilityCveId} />
272→                                            <br />
273→                                            <strong>Asset:</strong> {assetName}
274→                                        </div>
275→                                    </div>
276→                                </div>
277→
278→                                {/* Scope Field */}
279→                                <div className="mb-3">
280→                                    <label className="form-label">
281→                                        Exception Scope <span className="text-danger">*</span>
282→                                    </label>
283→                                    <div className="form-text mb-2">
284→                                        Choose whether to except only this specific vulnerability or all instances of this CVE across all assets.
285→                                    </div>
286→                                    <div className="form-check">
287→                                        <input
288→                                            className="form-check-input"
289→                                            type="radio"
290→                                            name="scope"
291→                                            id="scopeSingle"
292→                                            value="SINGLE_VULNERABILITY"
293→                                            checked={formData.scope === 'SINGLE_VULNERABILITY'}
294→                                            onChange={handleScopeChange}
295→                                            disabled={loading}
296→                                        />
297→                                        <label className="form-check-label" htmlFor="scopeSingle">
298→                                            <strong>Single Vulnerability</strong> - Only this specific vulnerability on {assetName}
299→                                        </label>
300→                                    </div>
301→                                    <div className="form-check">
302→                                        <input
303→                                            className="form-check-input"
304→                                            type="radio"
305→                                            name="scope"
306→                                            id="scopePattern"
307→                                            value="CVE_PATTERN"
308→                                            checked={formData.scope === 'CVE_PATTERN'}
309→                                            onChange={handleScopeChange}
310→                                            disabled={loading}
311→                                        />
312→                                        <label className="form-check-label" htmlFor="scopePattern">
313→                                            <strong>CVE Pattern</strong> - All instances of {vulnerabilityCveId || 'this CVE'} across all assets
314→                                        </label>
315→                                    </div>
316→                                </div>
317→
318→                                {/* Reason Field */}
319→                                <div className="mb-3">
320→                                    <label htmlFor="reason" className="form-label">
321→                                        Reason <span className="text-danger">*</span>
322→                                    </label>
323→                                    <textarea
324→                                        className={`form-control ${validationErrors.reason ? 'is-invalid' : ''}`}
325→                                        id="reason"
326→                                        name="reason"
327→                                        rows={6}
328→                                        placeholder="Provide a detailed justification for this exception request (minimum 50 characters)..."
329→                                        value={formData.reason}
330→                                        onChange={handleChange}
331→                                        disabled={loading}
332→                                        autoFocus
333→                                    ></textarea>
334→                                    {validationErrors.reason && (
335→                                        <div className="invalid-feedback d-block">
336→                                            {validationErrors.reason}
337→                                        </div>
338→                                    )}
339→                                    <div className={`form-text ${reasonCountColor}`}>
340→                                        {reasonLength} / 2048 characters (minimum 50 required)
341→                                    </div>
342→                                </div>
343→
344→                                {/* Expiration Date Field */}
345→                                <div className="mb-3">
346→                                    <label htmlFor="expirationDate" className="form-label">
347→                                        Expiration Date <span className="text-danger">*</span>
348→                                    </label>
349→                                    <input
350→                                        type="date"
351→                                        className={`form-control ${validationErrors.expirationDate ? 'is-invalid' : ''}`}
352→                                        id="expirationDate"
353→                                        name="expirationDate"
354→                                        value={formData.expirationDate}
355→                                        onChange={handleChange}
356→                                        disabled={loading}
357→                                        min={minDate}
358→                                    />
359→                                    {validationErrors.expirationDate && (
360→                                        <div className="invalid-feedback d-block">
361→                                            {validationErrors.expirationDate}
362→                                        </div>
363→                                    )}
364→                                    <div className="form-text">
365→                                        When should this exception expire? Must be a future date.
366→                                    </div>
367→                                </div>
368→
369→                                {/* Warning Text */}
370→                                <div className="alert alert-warning mb-0">
371→                                    <i className="bi bi-exclamation-triangle me-2"></i>
372→                                    <strong>Note:</strong> Your request will be reviewed by an administrator or security champion.
373→                                    You will be notified when your request is approved or rejected.
374→                                </div>
375→                            </div>
376→
377→                            {/* Footer */}
378→                            <div className="modal-footer">
379→                                <button
380→                                    type="button"
381→                                    className="btn btn-secondary"
382→                                    onClick={handleCancel}
383→                                    disabled={loading}
384→                                >
385→                                    Cancel
386→                                </button>
387→                                <button
388→                                    type="submit"
389→                                    className="btn btn-primary"
390→                                    disabled={loading}
391→                                >
392→                                    {loading ? (
393→                                        <>
394→                                            <span className="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true"></span>
395→                                            Submitting...
396→                                        </>
397→                                    ) : (
398→                                        <>
399→                                            <i className="bi bi-send me-2"></i>
400→                                            Submit Request
401→                                        </>
402→                                    )}
403→                                </button>
404→                            </div>
405→                        </form>
406→                    </div>
407→                </div>
408→            </div>
409→
410→            {/* Long Expiration Warning Modal */}
411→            {showLongExpirationWarning && (
412→                <div className="modal show d-block" tabIndex={-1} style={{ backgroundColor: 'rgba(0,0,0,0.5)' }}>
413→                    <div className="modal-dialog modal-dialog-centered">
414→                        <div className="modal-content">
415→                            <div className="modal-header bg-warning text-dark">
416→                                <h5 className="modal-title">
417→                                    <i className="bi bi-exclamation-triangle me-2"></i>
418→                                    Long Expiration Period
419→                                </h5>
420→                            </div>
421→                            <div className="modal-body">
422→                                <p className="mb-3">
423→                                    Exception expiration is more than <strong>365 days</strong> in the future.
424→                                </p>
425→                                <p className="mb-3">
426→                                    Security best practices recommend shorter exception periods with periodic review.
427→                                </p>
428→                                <p className="mb-0">
429→                                    Are you sure you want to continue with this expiration date?
430→                                </p>
431→                            </div>
432→                            <div className="modal-footer">
433→                                <button
434→                                    type="button"
435→                                    className="btn btn-secondary"
436→                                    onClick={handleRejectLongExpiration}
437→                                >
438→                                    No, Change Date
439→                                </button>
440→                                <button
441→                                    type="button"
442→                                    className="btn btn-warning"
443→                                    onClick={handleConfirmLongExpiration}
444→                                >
445→                                    Yes, Continue
446→                                </button>
447→                            </div>
448→                        </div>
449→                    </div>
450→                </div>
451→            )}
452→        </>
453→    );
454→};
455→
456→export default React.memo(ExceptionRequestModal);
