   1→/**
   2→ * Current Vulnerabilities Table Component
   3→ *
   4→ * Displays current vulnerabilities with filtering, sorting, and pagination capabilities
   5→ *
   6→ * Features:
   7→ * - Filter by severity, system, exception status, and overdue status
   8→ * - Sortable columns including overdue status
   9→ * - Exception and overdue status badges with tooltips
  10→ * - Pagination (50 items per page)
  11→ * - Loading and error states
  12→ *
  13→ * Related to: Feature 004-i-want-to (VULN Role & Vulnerability Management UI)
  14→ * Related to: Feature 021-vulnerability-overdue-exception-logic
  15→ */
  16→
  17→import React, { useState, useEffect } from "react";
  18→import {
  19→  getCurrentVulnerabilities,
  20→  cleanupDuplicateVulnerabilities,
  21→  getDistinctProducts,
  22→  getDistinctAdDomains,
  23→  getDistinctCloudAccountIds,
  24→  exportVulnerabilitiesServerSide,
  25→  cancelExportJob,
  26→  resetStuckExportJobs,
  27→  type CurrentVulnerability,
  28→  type PaginatedVulnerabilitiesResponse,
  29→  type VulnerabilityCleanupResult,
  30→  type ExportJob,
  31→} from "../services/vulnerabilityManagementService";
  32→import OverdueStatusBadge from "./OverdueStatusBadge";
  33→import ExceptionRequestModal from "./ExceptionRequestModal";
  34→import CveLink from "./CveLink";
  35→import { isAdmin, hasRole, hasVulnAccess } from "../utils/auth";
  36→import SearchableSelect from "./SearchableSelect";
  37→
  38→const CurrentVulnerabilitiesTable: React.FC = () => {
  39→  const [paginatedResponse, setPaginatedResponse] =
  40→    useState<PaginatedVulnerabilitiesResponse | null>(null);
  41→  const [loading, setLoading] = useState(true);
  42→  const [error, setError] = useState<string | null>(null);
  43→  const [successMessage, setSuccessMessage] = useState<string | null>(null);
  44→  const [hasAccess, setHasAccess] = useState(false);
  45→
  46→  // Exception request modal state
  47→  const [showRequestModal, setShowRequestModal] = useState(false);
  48→  const [selectedVulnerability, setSelectedVulnerability] =
  49→    useState<CurrentVulnerability | null>(null);
  50→
  51→  // Cleanup modal state
  52→  const [showCleanupModal, setShowCleanupModal] = useState(false);
  53→  const [cleanupResult, setCleanupResult] =
  54→    useState<VulnerabilityCleanupResult | null>(null);
  55→  const [cleanupLoading, setCleanupLoading] = useState(false);
  56→
  57→  // Export state
  58→  const [exportLoading, setExportLoading] = useState(false);
  59→  const [exportProgress, setExportProgress] = useState<ExportJob | null>(null);
  60→  const [exportJobId, setExportJobId] = useState<string | null>(null);
  61→
  62→  // Filter states
  63→  const [severityFilter, setSeverityFilter] = useState<string>("");
  64→  const [systemFilter, setSystemFilter] = useState<string>("");
  65→  const [exceptionFilter, setExceptionFilter] = useState<string>("not_excepted");
  66→  const [productFilter, setProductFilter] = useState<string>("");
  67→  const [adDomainFilter, setAdDomainFilter] = useState<string>("");
  68→  const [cloudAccountIdFilter, setCloudAccountIdFilter] = useState<string>("");
  69→
  70→  // Available filter options (lazy-loaded)
  71→  const [availableProducts, setAvailableProducts] = useState<string[]>([]);
  72→  const [availableAdDomains, setAvailableAdDomains] = useState<string[]>([]);
  73→  const [availableCloudAccountIds, setAvailableCloudAccountIds] = useState<
  74→    string[]
  75→  >([]);
  76→  const [productsLoaded, setProductsLoaded] = useState(false);
  77→  const [adDomainsLoaded, setAdDomainsLoaded] = useState(false);
  78→  const [cloudAccountIdsLoaded, setCloudAccountIdsLoaded] = useState(false);
  79→
  80→  // Pagination states
  81→  const [currentPage, setCurrentPage] = useState<number>(0);
  82→  const [pageSize] = useState<number>(50);
  83→
  84→  // Sort states
  85→  const [sortField, setSortField] =
  86→    useState<keyof CurrentVulnerability>("scanTimestamp");
  87→  const [sortOrder, setSortOrder] = useState<"asc" | "desc">("desc");
  88→
  89→  // Check access on mount - ADMIN, VULN, or SECCHAMPION
  90→  useEffect(() => {
  91→    const checkAccess = () => {
  92→      const isAuthorized = hasVulnAccess();
  93→      setHasAccess(isAuthorized);
  94→      setLoading(false);
  95→
  96→      if (!isAuthorized) {
  97→        setError(
  98→          "Access denied. This page is only accessible to ADMIN, VULN, and SECCHAMPION roles.",
  99→        );
 100→      }
 101→    };
 102→
 103→    checkAccess();
 104→
 105→    // Listen for user data updates
 106→    window.addEventListener("userLoaded", checkAccess);
 107→    return () => window.removeEventListener("userLoaded", checkAccess);
 108→  }, []);
 109→
 110→  useEffect(() => {
 111→    if (hasAccess) {
 112→      fetchVulnerabilities();
 113→    }
 114→  }, [
 115→    severityFilter,
 116→    systemFilter,
 117→    exceptionFilter,
 118→    productFilter,
 119→    adDomainFilter,
 120→    cloudAccountIdFilter,
 121→    currentPage,
 122→    sortField,
 123→    sortOrder,
 124→    hasAccess,
 125→  ]);
 126→
 127→  // Lazy-load filter options: load on first focus instead of on mount
 128→  const loadProducts = async () => {
 129→    if (productsLoaded || !hasAccess) return;
 130→    try {
 131→      const products = await getDistinctProducts(undefined, 1000);
 132→      setAvailableProducts(products);
 133→      setProductsLoaded(true);
 134→    } catch (err) {
 135→      console.error("Failed to fetch products:", err);
 136→    }
 137→  };
 138→
 139→  const loadAdDomains = async () => {
 140→    if (adDomainsLoaded || !hasAccess) return;
 141→    try {
 142→      const domains = await getDistinctAdDomains();
 143→      setAvailableAdDomains(domains);
 144→      setAdDomainsLoaded(true);
 145→    } catch (err) {
 146→      console.error("Failed to fetch AD domains:", err);
 147→    }
 148→  };
 149→
 150→  const loadCloudAccountIds = async () => {
 151→    if (cloudAccountIdsLoaded || !hasAccess) return;
 152→    try {
 153→      const accountIds = await getDistinctCloudAccountIds();
 154→      setAvailableCloudAccountIds(accountIds);
 155→      setCloudAccountIdsLoaded(true);
 156→    } catch (err) {
 157→      console.error("Failed to fetch cloud account IDs:", err);
 158→    }
 159→  };
 160→
 161→  const fetchVulnerabilities = async () => {
 162→    try {
 163→      setLoading(true);
 164→      // Map frontend field names to backend sort field names
 165→      const sortFieldMap: Record<string, string> = {
 166→        assetName: "assetName",
 167→        assetIp: "assetIp",
 168→        vulnerabilityId: "vulnerabilityId",
 169→        cvssSeverity: "cvssSeverity",
 170→        vulnerableProductVersions: "vulnerableProductVersions",
 171→        daysOpen: "daysOpen",
 172→        scanTimestamp: "scanTimestamp",
 173→        overdueStatus: "scanTimestamp", // Sort by scan age as proxy for overdue status
 174→      };
 175→      const backendSortField = sortFieldMap[sortField] || undefined;
 176→      const data = await getCurrentVulnerabilities(
 177→        severityFilter || undefined,
 178→        systemFilter || undefined,
 179→        exceptionFilter || undefined,
 180→        productFilter || undefined,
 181→        adDomainFilter || undefined,
 182→        cloudAccountIdFilter || undefined,
 183→        currentPage,
 184→        pageSize,
 185→        backendSortField,
 186→        sortOrder,
 187→      );
 188→      setPaginatedResponse(data);
 189→      setError(null);
 190→    } catch (err) {
 191→      setError(
 192→        err instanceof Error ? err.message : "Failed to fetch vulnerabilities",
 193→      );
 194→    } finally {
 195→      setLoading(false);
 196→    }
 197→  };
 198→
 199→  const handleFilterChange = () => {
 200→    // Reset to first page when filters change
 201→    setCurrentPage(0);
 202→  };
 203→
 204→  const handleRequestException = (vuln: CurrentVulnerability) => {
 205→    setSelectedVulnerability(vuln);
 206→    setShowRequestModal(true);
 207→  };
 208→
 209→  const handleModalClose = () => {
 210→    setShowRequestModal(false);
 211→    setSelectedVulnerability(null);
 212→  };
 213→
 214→  const handleRequestSuccess = () => {
 215→    setSuccessMessage(
 216→      "Exception request submitted successfully! Your request is pending review.",
 217→    );
 218→
 219→    // Auto-dismiss success message after 5 seconds
 220→    setTimeout(() => {
 221→      setSuccessMessage(null);
 222→    }, 5000);
 223→
 224→    // Refresh the vulnerability list
 225→    fetchVulnerabilities();
 226→  };
 227→
 228→  const handleCleanupDuplicates = async () => {
 229→    try {
 230→      setCleanupLoading(true);
 231→      const result = await cleanupDuplicateVulnerabilities();
 232→      setCleanupResult(result);
 233→      setShowCleanupModal(true);
 234→
 235→      // Refresh the vulnerability list after cleanup
 236→      fetchVulnerabilities();
 237→    } catch (err) {
 238→      setError(
 239→        err instanceof Error ? err.message : "Failed to cleanup duplicates",
 240→      );
 241→    } finally {
 242→      setCleanupLoading(false);
 243→    }
 244→  };
 245→
 246→  const handleCloseCleanupModal = () => {
 247→    setShowCleanupModal(false);
 248→    setCleanupResult(null);
 249→  };
 250→
 251→  /**
 252→   * Handle export of vulnerabilities to Excel
 253→   * Feature: Vulnerability Export Performance Optimization - Background Job Pattern
 254→   *
 255→   * Uses background job pattern with progress tracking:
 256→   * - Starts export job asynchronously
 257→   * - Polls for progress (updates UI every 2 seconds)
 258→   * - Downloads file when complete
 259→   * - Supports cancellation
 260→   */
 261→  const handleExport = async () => {
 262→    try {
 263→      setExportLoading(true);
 264→      setExportProgress(null);
 265→      setError(null);
 266→
 267→      // Use server-side export with progress tracking
 268→      await exportVulnerabilitiesServerSide((job) => {
 269→        setExportProgress(job);
 270→        setExportJobId(job.jobId);
 271→      });
 272→
 273→      setSuccessMessage("Export completed successfully!");
 274→      setTimeout(() => setSuccessMessage(null), 5000);
 275→
 276→    } catch (err) {
 277→      setError(
 278→        err instanceof Error ? err.message : "Failed to export vulnerabilities",
 279→      );
 280→    } finally {
 281→      setExportLoading(false);
 282→      setExportProgress(null);
 283→      setExportJobId(null);
 284→    }
 285→  };
 286→
 287→  /**
 288→   * Handle cancellation of running export
 289→   */
 290→  const handleCancelExport = async () => {
 291→    if (!exportJobId) return;
 292→
 293→    try {
 294→      await cancelExportJob(exportJobId);
 295→      setExportLoading(false);
 296→      setExportProgress(null);
 297→      setExportJobId(null);
 298→      setSuccessMessage("Export cancelled");
 299→      setTimeout(() => setSuccessMessage(null), 3000);
 300→    } catch (err) {
 301→      setError(
 302→        err instanceof Error ? err.message : "Failed to cancel export",
 303→      );
 304→    }
 305→  };
 306→
 307→  /**
 308→   * Handle reset of stuck export jobs
 309→   * Called when user encounters "already have an export in progress" error
 310→   */
 311→  const handleResetStuckExports = async () => {
 312→    try {
 313→      setExportLoading(true);
 314→      const result = await resetStuckExportJobs();
 315→      setSuccessMessage(result.message);
 316→      setTimeout(() => setSuccessMessage(null), 5000);
 317→      setError(null);
 318→    } catch (err) {
 319→      setError(
 320→        err instanceof Error ? err.message : "Failed to reset stuck exports",
 321→      );
 322→    } finally {
 323→      setExportLoading(false);
 324→    }
 325→  };
 326→
 327→  const handleSort = (field: keyof CurrentVulnerability) => {
 328→    if (sortField === field) {
 329→      setSortOrder(sortOrder === "asc" ? "desc" : "asc");
 330→    } else {
 331→      setSortField(field);
 332→      setSortOrder("asc");
 333→    }
 334→    setCurrentPage(0); // Reset to first page on sort change
 335→  };
 336→
 337→  const getSortedVulnerabilities = () => {
 338→    if (
 339→      !paginatedResponse ||
 340→      !paginatedResponse.content ||
 341→      !Array.isArray(paginatedResponse.content)
 342→    ) {
 343→      return [];
 344→    }
 345→    // Sorting is now server-side, return content as-is
 346→    return paginatedResponse.content;
 347→  };
 348→
 349→  const getSeverityBadgeClass = (severity: string | null): string => {
 350→    if (!severity) return "scand-neutral";
 351→    const sev = severity.toLowerCase();
 352→    if (sev.includes("critical")) return "scand-critical";
 353→    if (sev.includes("high")) return "scand-high";
 354→    if (sev.includes("medium")) return "scand-medium";
 355→    if (sev.includes("low")) return "scand-low";
 356→    return "scand-neutral";
 357→  };
 358→
 359→  const getExceptionBadge = (hasException: boolean, reason: string | null) => {
 360→    if (hasException) {
 361→      return (
 362→        <span
 363→          className="badge bg-success"
 364→          title={reason || "This vulnerability is excepted"}
 365→        >
 366→          Excepted
 367→        </span>
 368→      );
 369→    }
 370→    return (
 371→      <span className="badge bg-danger" title="No active exception">
 372→        Not Excepted
 373→      </span>
 374→    );
 375→  };
 376→
 377→  const SortIcon: React.FC<{ field: keyof CurrentVulnerability }> = ({
 378→    field,
 379→  }) => {
 380→    if (sortField !== field)
