        const response = await queryVulnerabilities(trimmedInput, forceRefresh, page, pageSize);
        console.log('[CrowdStrikeVulnerabilityLookup] Query successful:', response);

        // Auto-refresh if cached data is older than 120 minutes
        if (!forceRefresh && response.queriedAt) {
            const cacheAgeMinutes = calculateCacheAgeMinutes(response.queriedAt);
            if (cacheAgeMinutes > 120) {
                console.log(`[CrowdStrikeVulnerabilityLookup] Cache is ${cacheAgeMinutes} min old (>120), auto-refreshing from CrowdStrike`);
                const freshResponse = await queryVulnerabilities(trimmedInput, true, page, pageSize);
                console.log('[CrowdStrikeVulnerabilityLookup] Auto-refresh successful:', freshResponse);
                setQueryResponse(freshResponse);
                setCurrentPage(page);
                setError(null);
                setValidationError(null);
                return;
            }
        }

        setQueryResponse(response);
        setCurrentPage(page);
        setError(null);
        setValidationError(null);
    } catch (err) {
        console.error('[CrowdStrikeVulnerabilityLookup] Query failed:', err);
        setError(err instanceof Error ? err.message : 'Failed to query CrowdStrike');
        setQueryResponse(null);
    } finally {
        setLoading(false);
    }
};

/**
 * Handle refresh button click with cache bypass
 * Feature: 041-falcon-instance-lookup
 * Task: T039 [US3-Impl]
 */
const handleRefresh = () => {
    console.log('[CrowdStrikeVulnerabilityLookup] handleRefresh called with force=true');
    handleSearch(undefined, true, currentPage); // T039: Pass force=true to bypass cache
};

/**
 * Handle page change for pagination
 */
const handlePageChange = (newPage: number) => {
    console.log('[CrowdStrikeVulnerabilityLookup] handlePageChange called:', newPage);
    handleSearch(undefined, false, newPage);
};

/**
 * Handle save to database
 * Feature: 041-falcon-instance-lookup
 * Task: T057 [US3-Impl], T050 [US4-Impl]
 */
const handleSave = async () => {
    const vulnerabilities = queryResponse?.vulnerabilities ?? [];
    if (!queryResponse || vulnerabilities.length === 0) {
        setError('No vulnerabilities to save');
        return;
    }

    console.log('[CrowdStrikeVulnerabilityLookup] handleSave called');
    setSaving(true);
    setError(null);
    setSaveSuccess(null);

    try {
        // T050: Include instanceId in save request (Feature 041)
        const response = await saveVulnerabilities({
            hostname: queryResponse.hostname,
            vulnerabilities: vulnerabilities,
            instanceId: queryResponse.instanceId || undefined
        });
        console.log('[CrowdStrikeVulnerabilityLookup] Save successful:', response);

        // T014, T051: Update success message to show saved, skipped, created counts, and instance ID
        const parts = [];
        if (response.vulnerabilitiesSaved > 0) {
            parts.push(`${response.vulnerabilitiesSaved} vulnerabilities saved`);
        }
        if (response.vulnerabilitiesSkipped > 0) {
            parts.push(`${response.vulnerabilitiesSkipped} skipped`);
        }
        if (response.assetsCreated > 0) {
            parts.push(`${response.assetsCreated} asset created`);
        }

        // Feature 043: Add domain statistics to success message
        if (response.uniqueDomainCount !== undefined && response.uniqueDomainCount > 0) {
            const domainText = response.uniqueDomainCount === 1 ? 'domain' : 'domains';
            parts.push(`${response.uniqueDomainCount} unique ${domainText} discovered`);
        }

        // T051: Include instance ID in success message (Feature 041)
        let identifier = queryResponse.hostname;
        if (queryResponse.instanceId) {
            identifier = `${queryResponse.hostname} (Instance ID: ${queryResponse.instanceId})`;
        }

        let successMessage = parts.length > 0
            ? `Success: ${parts.join(', ')} for ${identifier}`
            : response.message;

        // Feature 043: Append domain list if present
        if (response.discoveredDomains && response.discoveredDomains.length > 0) {
            successMessage += `\nDomains: ${response.discoveredDomains.join(', ')}`;
        }

        setSaveSuccess(successMessage);

        // T015: If there are warnings/errors in the response, append them
        if (response.errors && response.errors.length > 0) {
            const errorSummary = response.errors.slice(0, 5).join('; ');
            const moreErrors = response.errors.length > 5 ? ` (and ${response.errors.length - 5} more...)` : '';
            setError(`Warnings: ${errorSummary}${moreErrors}`);
        }

        // Auto-dismiss success message after 5 seconds
        setTimeout(() => setSaveSuccess(null), 5000);
    } catch (err) {
        console.error('[CrowdStrikeVulnerabilityLookup] Save failed:', err);
        setError(err instanceof Error ? err.message : 'Failed to save vulnerabilities');
    } finally {
        setSaving(false);
    }
};

/**
 * Handle export to Excel
 * Exports the currently filtered vulnerabilities to an Excel file
 */
const handleExport = async () => {
    const vulnerabilities = sortedVulnerabilities;
    if (!queryResponse || vulnerabilities.length === 0) {
        setError('No vulnerabilities to export');
        return;
    }

    console.log('[CrowdStrikeVulnerabilityLookup] handleExport called');
    setExporting(true);
    setError(null);

    try {
        await exportVulnerabilitiesToExcel(vulnerabilities, {
            hostname: queryResponse.hostname,
            instanceId: queryResponse.instanceId,
            queriedAt: queryResponse.queriedAt,
        });
        console.log('[CrowdStrikeVulnerabilityLookup] Export successful');
    } catch (err) {
        console.error('[CrowdStrikeVulnerabilityLookup] Export failed:', err);
        setError(err instanceof Error ? err.message : 'Failed to export vulnerabilities');
    } finally {
        setExporting(false);
    }
};

/**
 * Get filtered vulnerabilities
 * Task: T039 [US2-Impl]
 */
const getFilteredVulnerabilities = (): CrowdStrikeVulnerabilityDto[] => {
    if (!queryResponse) return [];

    // Handle case where vulnerabilities is undefined/null (e.g., when totalCount is 0)
    const vulnerabilities = queryResponse.vulnerabilities ?? [];

    return vulnerabilities.filter(vuln => {
        // Severity filter
        if (severityFilter && vuln.severity !== severityFilter) return false;

        // Exception filter
        if (exceptionFilter === 'EXCEPTED' && !vuln.hasException) return false;
        if (exceptionFilter === 'NOT_EXCEPTED' && vuln.hasException) return false;

        // Product filter
        if (productFilter && !vuln.affectedProduct?.toLowerCase().includes(productFilter.toLowerCase())) {
            return false;
        }

        return true;
    });
};

/**
 * Get sorted vulnerabilities
 * Task: T043 [US2-Impl]
 */
const getSortedVulnerabilities = (filtered: CrowdStrikeVulnerabilityDto[]): CrowdStrikeVulnerabilityDto[] => {
    return [...filtered].sort((a, b) => {
        let aVal: any;
        let bVal: any;

        // Handle sorting for different field types
        if (sortField === 'severity') {
            // Custom severity order
            const severityOrder = { 'Critical': 4, 'High': 3, 'Medium': 2, 'Low': 1, 'Informational': 0 };
            aVal = severityOrder[a.severity as keyof typeof severityOrder] || 0;
            bVal = severityOrder[b.severity as keyof typeof severityOrder] || 0;
        } else if (sortField === 'daysOpen') {
            // Parse "X days" string to number
            aVal = parseInt(a.daysOpen?.split(' ')[0] || '0');
            bVal = parseInt(b.daysOpen?.split(' ')[0] || '0');
        } else if (sortField === 'detectedAt') {
            aVal = new Date(a.detectedAt).getTime();
            bVal = new Date(b.detectedAt).getTime();
        } else {
            aVal = (a as any)[sortField];
            bVal = (b as any)[sortField];
        }

        if (aVal === null || aVal === undefined) return 1;
        if (bVal === null || bVal === undefined) return -1;

        const comparison = aVal < bVal ? -1 : aVal > bVal ? 1 : 0;
        return sortOrder === 'asc' ? comparison : -comparison;
    });
};

/**
 * Handle sort
 * Task: T041 [US2-Impl]
 */
const handleSort = (field: string) => {
    if (sortField === field) {
        setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc');
    } else {
        setSortField(field);
        setSortOrder('asc');
    }
};

/**
 * Get severity badge class
 * Task: T035 [US1-Impl]
 */
const getSeverityBadgeClass = (severity: string): string => {
    const sev = severity.toLowerCase();
    if (sev.includes('critical')) return 'bg-danger';
    if (sev.includes('high')) return 'bg-warning text-dark';
    if (sev.includes('medium')) return 'bg-info text-dark';
    if (sev.includes('low')) return 'bg-success';
    return 'bg-secondary';
};

/**
 * Get exception badge
 * Task: T036 [US1-Impl]
 * Shows "N/A" when vulnerability is not yet overdue (< 30 days)
 */
const getExceptionBadge = (hasException: boolean, reason: string | null, daysOpen: string | null) => {
    if (hasException) {
        return (
            <span
                className="badge bg-success"
                title={reason || "This vulnerability is excepted"}
            >
                Excepted
            </span>
        );
    }

    // Parse days from string like "7 days"
    const days = parseInt(daysOpen?.split(' ')[0] || '0');

    // If under 30 days, exception not needed yet
    if (days < 30) {
        return <span className="badge bg-secondary" title="Exception not required yet (under 30 days)">N/A</span>;
    }

    return <span className="badge bg-danger" title="No active exception">Not Excepted</span>;
};

/**
 * Sort icon component
 * Task: T042 [US2-Impl]
 */
const SortIcon: React.FC<{ field: string }> = ({ field }) => {
    if (sortField !== field) return <i className="bi bi-chevron-expand ms-1 text-muted"></i>;
    return sortOrder === 'asc' ?
        <i className="bi bi-chevron-up ms-1"></i> :
        <i className="bi bi-chevron-down ms-1"></i>;
};

/**
 * Cache freshness badge component
 * Feature: 041-falcon-instance-lookup
 * Task: T038, T040 [US3-Impl]
 *
 * Displays cache age with color-coded badge:
 * - Green (success): Live data (< 1 minute)
 * - Blue (info): Fresh cache (1-5 minutes)
 * - Yellow (warning): Aging cache (5-10 minutes)
 * - Gray (secondary): Stale cache (10-15 minutes)
 */
const CacheFreshnessBadge: React.FC<{ queriedAt: string }> = ({ queriedAt }) => {
    const cacheAge = formatCacheAge(queriedAt);
    const badgeVariant = getCacheBadgeVariant(queriedAt);
    const icon = getCacheIcon(queriedAt);

    return (
        <span className={`badge bg-${badgeVariant} ms-2`} title={`Queried at: ${new Date(queriedAt).toLocaleString()}`}>
            <i className={`bi ${icon} me-1`}></i>
            {cacheAge}
        </span>
    );
};

const filteredVulnerabilities = getFilteredVulnerabilities();
const sortedVulnerabilities = getSortedVulnerabilities(filteredVulnerabilities);
const totalCount = queryResponse?.totalCount || 0;
const filteredCount = filteredVulnerabilities.length;
const totalPages = Math.ceil(totalCount / pageSize);
const rangeStart = currentPage * pageSize + 1;
const rangeEnd = Math.min((currentPage + 1) * pageSize, totalCount);

return (
    <div className="container-fluid p-4">
        <div className="row">
            <div className="col-12">
                <div className="d-flex justify-content-between align-items-center mb-4">
                    <h2>
                        <i className="bi bi-cloud-check me-2"></i>
                        CrowdStrike Vulnerability Lookup
                    </h2>
                </div>
            </div>
        </div>

        {/* Search Form - Tasks: T032 [US1-Impl], T025, T026, T027, T028 [US2-Impl] */}
        <div className="row mb-4">
            <div className="col-12">
                <div className="card">
                    <div className="card-body">
                        <h5 className="card-title">Query CrowdStrike Falcon</h5>
                        <form onSubmit={handleSearch}>
                            <div className="row g-3 align-items-end">
                                <div className="col-md-6">
                                    {/* T026: Updated label to include Instance ID */}
                                    <label htmlFor="hostname" className="form-label">
                                        System Hostname or Instance ID <span className="text-danger">*</span>
                                    </label>
                                    <input
                                        type="text"
                                        id="hostname"
                                        className={`form-control ${validationError ? 'is-invalid' : ''}`}
                                        placeholder="e.g., web-server-01 or i-0068f94221fe120df"
                                        value={hostname}
                                        onChange={(e) => handleInputChange(e.target.value)}
                                        required
                                        maxLength={255}
                                        disabled={loading}
                                    />
                                    {/* T028: Display validation error */}
                                    {validationError ? (
                                        <div className="invalid-feedback d-block">
                                            {validationError}
                                        </div>
                                    ) : (
                                        <small className="form-text text-muted">
                                            Enter the hostname or AWS EC2 Instance ID (e.g., i-0068f94221fe120df)
                                        </small>
                                    )}
                                </div>
                                <div className="col-md-6">
                                    <div className="d-flex gap-2">
                                        <button
                                            type="submit"
                                            className="btn btn-primary"
                                            disabled={loading || !hostname.trim()}
                                        >
                                            {loading ? (
                                                <>
                                                    <span className="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true"></span>
                                                    Searching...
                                                </>
                                            ) : (
                                                <>
                                                    <i className="bi bi-search me-2"></i>
                                                    Search
                                                </>
                                            )}
                                        </button>

                                        {/* Refresh Button - Task: T060 [US4-Impl] */}
                                        {queryResponse && (
                                            <button
                                                type="button"
                                                className="btn btn-outline-primary"
                                                onClick={handleRefresh}
                                                disabled={loading}
                                            >
                                                <i className="bi bi-arrow-clockwise me-2"></i>
                                                Refresh
                                            </button>
                                        )}
                                    </div>
                                </div>
                            </div>
                        </form>

