toolUseResult.originalFile:
/**
 * CrowdStrike Vulnerability Lookup Component
 *
 * Enables real-time querying of CrowdStrike Falcon API for system vulnerabilities
 *
 * Features:
 * - Search form with hostname or AWS instance ID input (Feature 041)
 * - Auto-detection of input type (hostname vs instance ID)
 * - Results table matching CurrentVulnerabilitiesTable design
 * - Filter by severity, exception status, product
 * - Sortable columns
 * - Save to database functionality
 * - Loading and error states
 *
 * Related to:
 * - Feature 015-we-have-currently (CrowdStrike System Vulnerability Lookup)
 * - Feature 041-falcon-instance-lookup (AWS Instance ID Support)
 * Tasks: T031-T036 [US1-Impl], T055-T058 [US3-Impl], T025-T029 [US2-Impl]
 */

import React, { useState, useEffect, useRef } from 'react';
import {
    queryVulnerabilities,
    saveVulnerabilities,
    type CrowdStrikeQueryResponse,
    type CrowdStrikeVulnerabilityDto
} from '../services/crowdstrikeService';
import {
    calculateCacheAgeMinutes,
    formatCacheAge,
    getCacheBadgeVariant,
    getCacheIcon
} from '../utils/cacheUtils';
import { exportVulnerabilitiesToExcel } from '../utils/vulnerabilityExport';
import CveLink from './CveLink';
import ExceptionRequestModal from './ExceptionRequestModal';

/**
 * AWS EC2 Instance ID validation regex
 * Feature: 041-falcon-instance-lookup
 * Task: T027
 *
 * Format: i-[0-9a-fA-F]{8,17}
 */
const AWS_INSTANCE_ID_REGEX = /^i-[0-9a-fA-F]{8,17}$/i;

/**
 * Check if input matches AWS instance ID pattern
 * Task: T027
 */
const isAwsInstanceId = (input: string): boolean => {
    return AWS_INSTANCE_ID_REGEX.test(input.trim());
};

const CrowdStrikeVulnerabilityLookup: React.FC = () => {
    // Search state
    const [hostname, setHostname] = useState<string>('');
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [validationError, setValidationError] = useState<string | null>(null);
    const [queryResponse, setQueryResponse] = useState<CrowdStrikeQueryResponse | null>(null);

    // Filter states
    const [severityFilter, setSeverityFilter] = useState<string>('');
    const [exceptionFilter, setExceptionFilter] = useState<string>('');
    const [productFilter, setProductFilter] = useState<string>('');

    // Sort states
    const [sortField, setSortField] = useState<string>('detectedAt');
    const [sortOrder, setSortOrder] = useState<'asc' | 'desc'>('desc');

    // Save state
    const [saving, setSaving] = useState(false);
    const [saveSuccess, setSaveSuccess] = useState<string | null>(null);

    // Export state
    const [exporting, setExporting] = useState(false);

    // Exception request modal state
    const [showRequestModal, setShowRequestModal] = useState(false);
    const [selectedVulnDbId, setSelectedVulnDbId] = useState<number | null>(null);
    const [selectedVulnCveId, setSelectedVulnCveId] = useState<string | null>(null);
    const [selectedVulnHostname, setSelectedVulnHostname] = useState('');
    const [requestSuccess, setRequestSuccess] = useState<string | null>(null);

    // Pagination state
    const [currentPage, setCurrentPage] = useState(0);
    const pageSize = 20000;

    // Track if initial search from URL param has been triggered
    const initialSearchDone = useRef(false);

    /**
     * Check for hostname in URL parameters and auto-search on mount
     * This enables deep-linking from other views (e.g., Domain Vulnerabilities)
     */
    useEffect(() => {
        // Only run once on mount
        if (initialSearchDone.current) return;

        const urlParams = new URLSearchParams(window.location.search);
        const hostnameParam = urlParams.get('hostname');

        if (hostnameParam) {
            console.log('[CrowdStrikeVulnerabilityLookup] Found hostname in URL:', hostnameParam);
            initialSearchDone.current = true;
            setHostname(hostnameParam);

            // Clean the URL to prevent re-search on refresh
            window.history.replaceState({}, '', '/vulnerabilities/system');

            // Trigger search after state is set
            // Use a small timeout to ensure state is updated
            setTimeout(async () => {
                setLoading(true);
                setError(null);
                setValidationError(null);
                setQueryResponse(null);

                try {
                    let response = await queryVulnerabilities(hostnameParam.trim(), false, 0, pageSize);
                    console.log('[CrowdStrikeVulnerabilityLookup] Auto-search successful:', response);

                    // Auto-refresh if cached data is older than 120 minutes
                    if (response.queriedAt) {
                        const cacheAgeMinutes = calculateCacheAgeMinutes(response.queriedAt);
                        if (cacheAgeMinutes > 120) {
                            console.log(`[CrowdStrikeVulnerabilityLookup] Cache is ${cacheAgeMinutes} min old (>120), auto-refreshing from CrowdStrike`);
                            response = await queryVulnerabilities(hostnameParam.trim(), true, 0, pageSize);
                        }
                    }

                    setQueryResponse(response);
                } catch (err) {
                    console.error('[CrowdStrikeVulnerabilityLookup] Auto-search failed:', err);
                    setError(err instanceof Error ? err.message : 'Failed to query CrowdStrike');
                } finally {
                    setLoading(false);
                }
            }, 0);
        }
    }, []);

    /**
     * Handle input change with validation
     * Feature: 041-falcon-instance-lookup
     * Task: T027, T028, T029
     */
    const handleInputChange = (value: string) => {
        setHostname(value);
        setValidationError(null); // Clear validation error when user types (T029)
        setError(null); // Clear general error
    };

    /**
     * Validate input before search
     * Feature: 041-falcon-instance-lookup
     * Task: T027, T028
     */
    const validateInput = (input: string): boolean => {
        const trimmed = input.trim();

        if (!trimmed) {
            setValidationError('Please enter a hostname or instance ID');
            return false;
        }

        // If it looks like an instance ID, validate the format
        if (trimmed.startsWith('i-')) {
            if (!isAwsInstanceId(trimmed)) {
                setValidationError(
                    "Invalid instance ID format. Expected 'i-' followed by 8 or 17 hexadecimal characters (e.g., i-0068f94221fe120df)"
                );
                return false;
            }
        }

        return true;
    };

    /**
     * Handle search form submission
     * Feature: 041-falcon-instance-lookup
     * Tasks: T033 [US1-Impl], T027, T028 [US2-Impl], T039 [US3-Impl]
     *
     * @param e Form event (optional)
     * @param forceRefresh If true, bypass cache (Feature 041, Task T039)
     */
    const handleSearch = async (e?: React.FormEvent, forceRefresh: boolean = false, page: number = 0) => {
        if (e) e.preventDefault();

        // Validate input (T027, T028)
        if (!validateInput(hostname)) {
            return;
        }

        const trimmedInput = hostname.trim();
        const inputType = isAwsInstanceId(trimmedInput) ? 'instance ID' : 'hostname';

        console.log(`[CrowdStrikeVulnerabilityLookup] handleSearch called: ${inputType} = ${trimmedInput}, force = ${forceRefresh}, page = ${page}`);
        setLoading(true);
        setError(null);
        setValidationError(null);
        setQueryResponse(null);
        setSaveSuccess(null);

        try {
            const response = await queryVulnerabilities(trimmedInput, forceRefresh, page, pageSize);
            console.log('[CrowdStrikeVulnerabilityLookup] Query successful:', response);

            // Auto-refresh if cached data is older than 120 minutes
            if (!forceRefresh && response.queriedAt) {
                const cacheAgeMinutes = calculateCacheAgeMinutes(response.queriedAt);
                if (cacheAgeMinutes > 120) {
                    console.log(`[CrowdStrikeVulnerabilityLookup] Cache is ${cacheAgeMinutes} min old (>120), auto-refreshing from CrowdStrike`);
                    const freshResponse = await queryVulnerabilities(trimmedInput, true, page, pageSize);
                    console.log('[CrowdStrikeVulnerabilityLookup] Auto-refresh successful:', freshResponse);
                    setQueryResponse(freshResponse);
                    setCurrentPage(page);
                    setError(null);
                    setValidationError(null);
                    return;
                }
            }

            setQueryResponse(response);
            setCurrentPage(page);
            setError(null);
            setValidationError(null);
        } catch (err) {
            console.error('[CrowdStrikeVulnerabilityLookup] Query failed:', err);
            setError(err instanceof Error ? err.message : 'Failed to query CrowdStrike');
            setQueryResponse(null);
        } finally {
            setLoading(false);
        }
    };

    /**
     * Handle refresh button click with cache bypass
     * Feature: 041-falcon-instance-lookup
     * Task: T039 [US3-Impl]
     */
    const handleRefresh = () => {
        console.log('[CrowdStrikeVulnerabilityLookup] handleRefresh called with force=true');
        handleSearch(undefined, true, currentPage); // T039: Pass force=true to bypass cache
    };

    /**
     * Handle page change for pagination
     */
    const handlePageChange = (newPage: number) => {
        console.log('[CrowdStrikeVulnerabilityLookup] handlePageChange called:', newPage);
        handleSearch(undefined, false, newPage);
    };

    /**
     * Handle save to database
     * Feature: 041-falcon-instance-lookup
     * Task: T057 [US3-Impl], T050 [US4-Impl]
     */
    const handleSave = async () => {
        const vulnerabilities = queryResponse?.vulnerabilities ?? [];
        if (!queryResponse || vulnerabilities.length === 0) {
            setError('No vulnerabilities to save');
            return;
        }

        console.log('[CrowdStrikeVulnerabilityLookup] handleSave called');
        setSaving(true);
        setError(null);
        setSaveSuccess(null);

        try {
            // T050: Include instanceId in save request (Feature 041)
            const response = await saveVulnerabilities({
                hostname: queryResponse.hostname,
                vulnerabilities: vulnerabilities,
                instanceId: queryResponse.instanceId || undefined
            });
            console.log('[CrowdStrikeVulnerabilityLookup] Save successful:', response);

            // T014, T051: Update success message to show saved, skipped, created counts, and instance ID
            const parts = [];
            if (response.vulnerabilitiesSaved > 0) {
                parts.push(`${response.vulnerabilitiesSaved} vulnerabilities saved`);
            }
            if (response.vulnerabilitiesSkipped > 0) {
                parts.push(`${response.vulnerabilitiesSkipped} skipped`);
            }
            if (response.assetsCreated > 0) {
                parts.push(`${response.assetsCreated} asset created`);
            }

            // Feature 043: Add domain statistics to success message
            if (response.uniqueDomainCount !== undefined && response.uniqueDomainCount > 0) {
                const domainText = response.uniqueDomainCount === 1 ? 'domain' : 'domains';
                parts.push(`${response.uniqueDomainCount} unique ${domainText} discovered`);
            }

            // T051: Include instance ID in success message (Feature 041)
            let identifier = queryResponse.hostname;
            if (queryResponse.instanceId) {
                identifier = `${queryResponse.hostname} (Instance ID: ${queryResponse.instanceId})`;
            }

            let successMessage = parts.length > 0
                ? `Success: ${parts.join(', ')} for ${identifier}`
                : response.message;

            // Feature 043: Append domain list if present
            if (response.discoveredDomains && response.discoveredDomains.length > 0) {
                successMessage += `\nDomains: ${response.discoveredDomains.join(', ')}`;
            }

            setSaveSuccess(successMessage);

            // T015: If there are warnings/errors in the response, append them
            if (response.errors && response.errors.length > 0) {
                const errorSummary = response.errors.slice(0, 5).join('; ');
                const moreErrors = response.errors.length > 5 ? ` (and ${response.errors.length - 5} more...)` : '';
                setError(`Warnings: ${errorSummary}${moreErrors}`);
            }

            // Auto-dismiss success message after 5 seconds
            setTimeout(() => setSaveSuccess(null), 5000);
        } catch (err) {
            console.error('[CrowdStrikeVulnerabilityLookup] Save failed:', err);
            setError(err instanceof Error ? err.message : 'Failed to save vulnerabilities');
        } finally {
            setSaving(false);
        }
    };

    /**
     * Handle export to Excel
     * Exports the currently filtered vulnerabilities to an Excel file
     */
    const handleExport = async () => {
        const vulnerabilities = sortedVulnerabilities;
        if (!queryResponse || vulnerabilities.length === 0) {
            setError('No vulnerabilities to export');
            return;
        }

        console.log('[CrowdStrikeVulnerabilityLookup] handleExport called');
        setExporting(true);
        setError(null);

        try {
            await exportVulnerabilitiesToExcel(vulnerabilities, {
                hostname: queryResponse.hostname,
                instanceId: queryResponse.instanceId,
                queriedAt: queryResponse.queriedAt,
            });
            console.log('[CrowdStrikeVulnerabilityLookup] Export successful');
        } catch (err) {
            console.error('[CrowdStrikeVulnerabilityLookup] Export failed:', err);
            setError(err instanceof Error ? err.message : 'Failed to export vulnerabilities');
        } finally {
            setExporting(false);
        }
    };

    /**
     * Get filtered vulnerabilities
     * Task: T039 [US2-Impl]
     */
    const getFilteredVulnerabilities = (): CrowdStrikeVulnerabilityDto[] => {
        if (!queryResponse) return [];

        // Handle case where vulnerabilities is undefined/null (e.g., when totalCount is 0)
        const vulnerabilities = queryResponse.vulnerabilities ?? [];

        return vulnerabilities.filter(vuln => {
            // Severity filter
            if (severityFilter && vuln.severity !== severityFilter) return false;

            // Exception filter
            if (exceptionFilter === 'EXCEPTED' && !vuln.hasException) return false;
            if (exceptionFilter === 'NOT_EXCEPTED' && vuln.hasException) return false;

            // Product filter
            if (productFilter && !vuln.affectedProduct?.toLowerCase().includes(productFilter.toLowerCase())) {
                return false;
            }

            return true;
        });
    };

    /**
     * Get sorted vulnerabilities
     * Task: T043 [US2-Impl]
     */
    const getSortedVulnerabilities = (filtered: CrowdStrikeVulnerabilityDto[]): CrowdStrikeVulnerabilityDto[] => {
        return [...filtered].sort((a, b) => {
            let aVal: any;
            let bVal: any;

            // Handle sorting for different field types
            if (sortField === 'severity') {
                // Custom severity order
                const severityOrder = { 'Critical': 4, 'High': 3, 'Medium': 2, 'Low': 1, 'Informational': 0 };
                aVal = severityOrder[a.severity as keyof typeof severityOrder] || 0;
                bVal = severityOrder[b.severity as keyof typeof severityOrder] || 0;
            } else if (sortField === 'daysOpen') {
                // Parse "X days" string to number
                aVal = parseInt(a.daysOpen?.split(' ')[0] || '0');
                bVal = parseInt(b.daysOpen?.split(' ')[0] || '0');
            } else if (sortField === 'detectedAt') {
                aVal = new Date(a.detectedAt).getTime();
                bVal = new Date(b.detectedAt).getTime();
            } else {
                aVal = (a as any)[sortField];
                bVal = (b as any)[sortField];
            }

            if (aVal === null || aVal === undefined) return 1;
            if (bVal === null || bVal === undefined) return -1;

            const comparison = aVal < bVal ? -1 : aVal > bVal ? 1 : 0;
            return sortOrder === 'asc' ? comparison : -comparison;
        });
    };

    /**
     * Handle sort
     * Task: T041 [US2-Impl]
     */
    const handleSort = (field: string) => {
        if (sortField === field) {
            setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc');
        } else {
            setSortField(field);
            setSortOrder('asc');
        }
    };

    /**
     * Get severity badge class
     * Task: T035 [US1-Impl]
     */
    const getSeverityBadgeClass = (severity: string): string => {
        const sev = severity.toLowerCase();
        if (sev.includes('critical')) return 'bg-danger';
        if (sev.includes('high')) return 'bg-warning text-dark';
        if (sev.includes('medium')) return 'bg-info text-dark';
        if (sev.includes('low')) return 'bg-success';
        return 'bg-secondary';
    };

    /**
     * Get exception badge
     * Task: T036 [US1-Impl]
     * Shows "N/A" when vulnerability is not yet overdue (< 30 days)
     */
    const getExceptionBadge = (hasException: boolean, reason: string | null, daysOpen: string | null) => {
        if (hasException) {
            return (
                <span
                    className="badge bg-success"
                    title={reason || "This vulnerability is excepted"}
                >
                    Excepted
                </span>
            );
        }

        // Parse days from string like "7 days"
        const days = parseInt(daysOpen?.split(' ')[0] || '0');

        // If under 30 days, exception not needed yet
        if (days < 30) {
            return <span className="badge bg-secondary" title="Exception not required yet (under 30 days)">N/A</span>;
        }

        return <span className="badge bg-danger" title="No active exception">Not Excepted</span>;
    };

    /**
     * Sort icon component
     * Task: T042 [US2-Impl]
     */
    const SortIcon: React.FC<{ field: string }> = ({ field }) => {
        if (sortField !== field) return <i className="bi bi-chevron-expand ms-1 text-muted"></i>;
        return sortOrder === 'asc' ?
            <i className="bi bi-chevron-up ms-1"></i> :
            <i className="bi bi-chevron-down ms-1"></i>;
    };

    /**
     * Cache freshness badge component
     * Feature: 041-falcon-instance-lookup
     * Task: T038, T040 [US3-Impl]
     *
     * Displays cache age with color-coded badge:
     * - Green (success): Live data (< 1 minute)
     * - Blue (info): Fresh cache (1-5 minutes)
     * - Yellow (warning): Aging cache (5-10 minutes)
     * - Gray (secondary): Stale cache (10-15 minutes)
     */
    const CacheFreshnessBadge: React.FC<{ queriedAt: string }> = ({ queriedAt }) => {
        const cacheAge = formatCacheAge(queriedAt);
        const badgeVariant = getCacheBadgeVariant(queriedAt);
        const icon = getCacheIcon(queriedAt);

        return (
            <span className={`badge bg-${badgeVariant} ms-2`} title={`Queried at: ${new Date(queriedAt).toLocaleString()}`}>
                <i className={`bi ${icon} me-1`}></i>
                {cacheAge}
            </span>
        );
    };

    const filteredVulnerabilities = getFilteredVulnerabilities();
    const sortedVulnerabilities = getSortedVulnerabilities(filteredVulnerabilities);
    const totalCount = queryResponse?.totalCount || 0;
    const filteredCount = filteredVulnerabilities.length;
    const totalPages = Math.ceil(totalCount / pageSize);
    const rangeStart = currentPage * pageSize + 1;
    const rangeEnd = Math.min((currentPage + 1) * pageSize, totalCount);

    return (
        <div className="container-fluid p-4">
            <div className="row">
                <div className="col-12">
                    <div className="d-flex justify-content-between align-items-center mb-4">
                        <h2>
                            <i className="bi bi-cloud-check me-2"></i>
                            CrowdStrike Vulnerability Lookup
                        </h2>
                    </div>
                </div>
            </div>

            {/* Search Form - Tasks: T032 [US1-Impl], T025, T026, T027, T028 [US2-Impl] */}
            <div className="row mb-4">
                <div className="col-12">
                    <div className="card">
                        <div className="card-body">
                            <h5 className="card-title">Query CrowdStrike Falcon</h5>
                            <form onSubmit={handleSearch}>
                                <div className="row g-3 align-items-end">
                                    <div className="col-md-6">
                                        {/* T026: Updated label to include Instance ID */}
                                        <label htmlFor="hostname" className="form-label">
                                            System Hostname or Instance ID <span className="text-danger">*</span>
                                        </label>
                                        <input
                                            type="text"
                                            id="hostname"
                                            className={`form-control ${validationError ? 'is-invalid' : ''}`}
                                            placeholder="e.g., web-server-01 or i-0068f94221fe120df"
                                            value={hostname}
                                            onChange={(e) => handleInputChange(e.target.value)}
                                            required
                                            maxLength={255}
                                            disabled={loading}
                                        />
                                        {/* T028: Display validation error */}
                                        {validationError ? (
                                            <div className="invalid-feedback d-block">
                                                {validationError}
                                            </div>
                                        ) : (
                                            <small className="form-text text-muted">
                                                Enter the hostname or AWS EC2 Instance ID (e.g., i-0068f94221fe120df)
                                            </small>
                                        )}
                                    </div>
                                    <div className="col-md-6">
                                        <div className="d-flex gap-2">
                                            <button
                                                type="submit"
                                                className="btn btn-primary"
                                                disabled={loading || !hostname.trim()}
                                            >
                                                {loading ? (
                                                    <>
                                                        <span className="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true"></span>
                                                        Searching...
                                                    </>
                                                ) : (
                                                    <>
                                                        <i className="bi bi-search me-2"></i>
                                                        Search
                                                    </>
                                                )}
                                            </button>

                                            {/* Refresh Button - Task: T060 [US4-Impl] */}
                                            {queryResponse && (
                                                <button
                                                    type="button"
                                                    className="btn btn-outline-primary"
                                                    onClick={handleRefresh}
                                                    disabled={loading}
                                                >
                                                    <i className="bi bi-arrow-clockwise me-2"></i>
                                                    Refresh
                                                </button>
                                            )}
                                        </div>
                                    </div>
                                </div>
                            </form>
                        </div>
                    </div>
                </div>
            </div>

            {/* Error Alert */}
            {error && (
                <div className="row mb-4">
                    <div className="col-12">
                        <div className="alert alert-danger alert-dismissible fade show" role="alert">
                            <i className="bi bi-exclamation-triangle me-2"></i>
                            {error}
                            <button
                                type="button"
                                className="btn-close"
                                onClick={() => setError(null)}
                                aria-label="Close"
                            ></button>
                        </div>
                    </div>
                </div>
            )}

            {/* Success Alert - Task: T058 [US3-Impl] */}
            {saveSuccess && (
                <div className="row mb-4">
                    <div className="col-12">
                        <div className="alert alert-success alert-dismissible fade show" role="alert">
                            <i className="bi bi-check-circle me-2"></i>
                            {saveSuccess}
                            <button
                                type="button"
                                className="btn-close"
                                onClick={() => setSaveSuccess(null)}
                                aria-label="Close"
                            ></button>
                        </div>
                    </div>
                </div>
            )}

            {/* Results Section - Task: T034 [US1-Impl] */}
            {queryResponse && (
                <>
                    {/* Filters - Task: T038 [US2-Impl] */}
                    <div className="row mb-4">
                        <div className="col-md-4">
                            <label htmlFor="severityFilter" className="form-label">Severity</label>
                            <select
                                id="severityFilter"
                                className="form-select"
                                value={severityFilter}
                                onChange={(e) => setSeverityFilter(e.target.value)}
                            >
                                <option value="">All Severities</option>
                                <option value="Critical">Critical</option>
                                <option value="High">High</option>
                                <option value="Medium">Medium</option>
                                <option value="Low">Low</option>
                            </select>
                        </div>
                        <div className="col-md-4">
                            <label htmlFor="exceptionFilter" className="form-label">Exception Status</label>
                            <select
                                id="exceptionFilter"
                                className="form-select"
                                value={exceptionFilter}
                                onChange={(e) => setExceptionFilter(e.target.value)}
                            >
                                <option value="">All Statuses</option>
                                <option value="EXCEPTED">Excepted</option>
                                <option value="NOT_EXCEPTED">Not Excepted</option>
                            </select>
                        </div>
                        <div className="col-md-4">
                            <label htmlFor="productFilter" className="form-label">Product</label>
                            <input
                                type="text"
                                id="productFilter"
                                className="form-control"
                                placeholder="Filter by product..."
                                value={productFilter}
                                onChange={(e) => setProductFilter(e.target.value)}
                            />
                        </div>
                    </div>

                    {/* Results Table */}
                    <div className="row">
                        <div className="col-12">
                            <div className="card">
                                <div className="card-body">
                                    <div className="d-flex justify-content-between align-items-center mb-3">
                                        <div>
                                            <h5 className="card-title mb-0">
                                                Vulnerabilities for {queryResponse.hostname}
                                                <span className="text-muted ms-2">
                                                    {totalCount > pageSize
                                                        ? `(Showing ${rangeStart.toLocaleString()}-${rangeEnd.toLocaleString()} of ${totalCount.toLocaleString()} total)`
                                                        : `(${totalCount.toLocaleString()} total)`
                                                    }
                                                </span>
                                                {/* T040: Display cache freshness badge */}
                                                <CacheFreshnessBadge queriedAt={queryResponse.queriedAt} />
                                            </h5>
                                            {/* Feature 041: Display instance ID and device count when querying by instance ID */}
                                            {queryResponse.instanceId && (
                                                <small className="text-muted">
                                                    Instance ID: <code>{queryResponse.instanceId}</code>
                                                    {queryResponse.deviceCount && queryResponse.deviceCount > 1 && (
                                                        <span className="ms-2">
                                                            ({queryResponse.deviceCount} devices found)
                                                        </span>
                                                    )}
                                                </small>
                                            )}
                                        </div>

                                        {/* Action Buttons */}
                                        {sortedVulnerabilities.length > 0 && (
                                            <div className="d-flex gap-2">
                                                {/* Export Button */}
                                                <button
                                                    className="btn btn-outline-success"
                                                    onClick={handleExport}
                                                    disabled={exporting}
                                                >
                                                    {exporting ? (
                                                        <>
                                                            <span className="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true"></span>
                                                            Exporting...
                                                        </>
                                                    ) : (
                                                        <>
                                                            <i className="bi bi-file-earmark-excel me-2"></i>
                                                            Export to Excel
                                                        </>
                                                    )}
                                                </button>

                                                {/* Save Button - Task: T055 [US3-Impl] */}
                                                <button
                                                    className="btn btn-primary"
                                                    onClick={handleSave}
                                                    disabled={saving}
                                                >
                                                    {saving ? (
                                                        <>
                                                            <span className="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true"></span>
                                                            Saving...
                                                        </>
                                                    ) : (
                                                        <>
                                                            <i className="bi bi-database-add me-2"></i>
                                                            Save to Database
                                                        </>
                                                    )}
                                                </button>
                                            </div>
                                        )}
                                    </div>

                                    {sortedVulnerabilities.length === 0 ? (
                                        <p className="text-muted">
                                            {(queryResponse.vulnerabilities?.length ?? 0) === 0
                                                ? 'No vulnerabilities found for this system.'
                                                : 'No vulnerabilities match the current filters.'}
                                        </p>
                                    ) : (
                                        <>
                                        <div className="table-responsive">
                                            <table className="table table-striped table-hover">
                                                <thead>
                                                    <tr>
                                                        <th
                                                            onClick={() => handleSort('cveId')}
                                                            style={{ cursor: 'pointer' }}
                                                        >
                                                            CVE
                                                            <SortIcon field="cveId" />
                                                        </th>
                                                        <th
                                                            onClick={() => handleSort('severity')}
                                                            style={{ cursor: 'pointer' }}
                                                        >
                                                            Severity
                                                            <SortIcon field="severity" />
                                                        </th>
                                                        <th
                                                            onClick={() => handleSort('affectedProduct')}
                                                            style={{ cursor: 'pointer' }}
                                                        >
                                                            Product
                                                            <SortIcon field="affectedProduct" />
                                                        </th>
                                                        <th
                                                            onClick={() => handleSort('daysOpen')}
                                                            style={{ cursor: 'pointer' }}
                                                        >
                                                            Days Open
                                                            <SortIcon field="daysOpen" />
                                                        </th>
                                                        <th
                                                            onClick={() => handleSort('hasException')}
                                                            style={{ cursor: 'pointer' }}
                                                        >
                                                            Exception
                                                            <SortIcon field="hasException" />
                                                        </th>
                                                        <th>AWS Account</th>
                                                    </tr>
                                                </thead>
                                                <tbody>
                                                    {sortedVulnerabilities.map((vuln) => (
                                                        <tr key={vuln.id}>
                                                            <td>
                                                                <CveLink cveId={vuln.cveId} />
                                                            </td>
                                                            <td>
                                                                <span className={`badge ${getSeverityBadgeClass(vuln.severity)}`}>
                                                                    {vuln.severity}
                                                                </span>
                                                            </td>
                                                            <td style={{ maxWidth: '200px', overflow: 'hidden', textOverflow: 'ellipsis' }}>
                                                                {vuln.affectedProduct || '-'}
                                                            </td>
                                                            <td>{vuln.daysOpen || '-'}</td>
                                                            <td>
                                                                {getExceptionBadge(vuln.hasException, vuln.exceptionReason, vuln.daysOpen)}
                                                            </td>
                                                            <td>{queryResponse?.cloudAccountId || '-'}</td>
                                                        </tr>
                                                    ))}
                                                </tbody>
                                            </table>
                                        </div>

                                        {/* Pagination Controls */}
                                        {totalPages > 1 && (
                                            <nav aria-label="Vulnerability pagination" className="mt-3">
                                                <div className="d-flex justify-content-between align-items-center">
                                                    <small className="text-muted">
                                                        Page {currentPage + 1} of {totalPages.toLocaleString()}
                                                    </small>
                                                    <ul className="pagination mb-0">
                                                        <li className={`page-item ${currentPage === 0 ? 'disabled' : ''}`}>
                                                            <button
                                                                className="page-link"
                                                                onClick={() => handlePageChange(0)}
                                                                disabled={currentPage === 0 || loading}
                                                            >
                                                                First
                                                            </button>
                                                        </li>
                                                        <li className={`page-item ${currentPage === 0 ? 'disabled' : ''}`}>
                                                            <button
                                                                className="page-link"
                                                                onClick={() => handlePageChange(currentPage - 1)}
                                                                disabled={currentPage === 0 || loading}
                                                            >
                                                                Previous
                                                            </button>
                                                        </li>
                                                        <li className={`page-item ${currentPage >= totalPages - 1 ? 'disabled' : ''}`}>
                                                            <button
                                                                className="page-link"
                                                                onClick={() => handlePageChange(currentPage + 1)}
                                                                disabled={currentPage >= totalPages - 1 || loading}
                                                            >
                                                                Next
                                                            </button>
                                                        </li>
                                                        <li className={`page-item ${currentPage >= totalPages - 1 ? 'disabled' : ''}`}>
                                                            <button
                                                                className="page-link"
                                                                onClick={() => handlePageChange(totalPages - 1)}
                                                                disabled={currentPage >= totalPages - 1 || loading}
                                                            >
                                                                Last
                                                            </button>
                                                        </li>
                                                    </ul>
                                                </div>
                                            </nav>
                                        )}
                                        </>
                                    )}
                                </div>
                            </div>
                        </div>
                    </div>
                </>
            )}

            {/* Back to Home button */}
            <div className="row mt-4">
                <div className="col-12">
                    <a href="/" className="btn btn-secondary">
                        <i className="bi bi-house me-2"></i>
                        Back to Home
                    </a>
                </div>
            </div>
        </div>
    );
};

export default CrowdStrikeVulnerabilityLookup;

