 38→    38→/**
 39→    39→ * AWS EC2 Instance ID validation regex
 40→    40→ * Feature: 041-falcon-instance-lookup
 41→    41→ * Task: T027
 42→    42→ *
 43→    43→ * Format: i-[0-9a-fA-F]{8,17}
 44→    44→ */
 45→    45→const AWS_INSTANCE_ID_REGEX = /^i-[0-9a-fA-F]{8,17}$/i;
 46→    46→
 47→    47→/**
 48→    48→ * Check if input matches AWS instance ID pattern
 49→    49→ * Task: T027
 50→    50→ */
 51→    51→const isAwsInstanceId = (input: string): boolean => {
 52→    52→    return AWS_INSTANCE_ID_REGEX.test(input.trim());
 53→    53→};
 54→    54→
 55→    55→const CrowdStrikeVulnerabilityLookup: React.FC = () => {
 56→    56→    // Search state
