122→   122→                    console.log('[CrowdStrikeVulnerabilityLookup] Auto-search successful:', response);
123→   123→
124→   124→                    // Auto-refresh if cached data is older than 120 minutes
125→   125→                    if (response.queriedAt) {
126→   126→                        const cacheAgeMinutes = calculateCacheAgeMinutes(response.queriedAt);
127→   127→                        if (cacheAgeMinutes > 120) {
